    @Test
    fun testIsActiveWithEmptyContext() {
        // CoroutineContext.isActive should return true when there's no Job
        assertTrue(EmptyCoroutineContext.isActive)
        assertTrue((Dispatchers.Default).isActive)
        assertTrue((CoroutineName("test")).isActive)

        // But Job.isActive should still follow the normal Job lifecycle
        val completedJob = Job()
        completedJob.complete()
        assertFalse(completedJob.isActive)

        // Context with completed job should be inactive
        assertFalse((EmptyCoroutineContext + completedJob).isActive)
    }"}

